const body = items[0].json.body;
const data = body.data;
const key = data.key;
const msg = data.message;

// Extrai texto independente do tipo de mensagem
const texto = msg?.conversation 
  || msg?.extendedTextMessage?.text 
  || msg?.imageMessage?.caption
  || msg?.documentMessage?.caption
  || '[mensagem sem texto]';

const telefone = key.remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');

return [{
  json: {
    message_id: key.id,
    remoteJid: key.remoteJid,
    telefone: telefone,
    instance: body.instance,
    mensagem_usuario: texto,
    timestamp_wpp: data.messageTimestamp,
    tipo_mensagem: Object.keys(msg || {})[0] || 'conversation'
  }
}];

