parameters.jsCode:
// === EXTRAГҮГғO ROBUSTA (protege contra array-in-item e resposta vazia) ===
const rawLoja = $('Supabase - Carregar Config da Loja (Tenant)').first()?.json;
const loja = Array.isArray(rawLoja) ? (rawLoja[0] || {}) : (rawLoja || {});

const rawHistorico = $('Supabase - Carregar HistГіrico de Conversa (Гәltimas 25)').all().map(i => i.json);
const historico = rawHistorico.flatMap(h => Array.isArray(h) ? h : [h]).filter(Boolean);

const rawLead = $('Supabase - Buscar ou Criar Lead (Upsert)').first()?.json;
const lead = Array.isArray(rawLead) ? (rawLead[0] || {}) : (rawLead || {});

const payloadNode = $('Code - Extrair Campos do Payload').first().json;

// === HORГҒRIO BRASIL (Intl API вҖ” funciona independente do timezone do servidor) ===
const agora = new Date();
const formatter = new Intl.DateTimeFormat('pt-BR', { timeZone: 'America/Sao_Paulo', hour: 'numeric', minute: 'numeric', weekday: 'short', hour12: false });
const parts = formatter.formatToParts(agora);
const hBR = Number(parts.find(p => p.type === 'hour')?.value || 0);
const mBR = Number(parts.find(p => p.type === 'minute')?.value || 0);
const dayName = (parts.find(p => p.type === 'weekday')?.value || '').toLowerCase().replace('.','');
const minutosAgora = hBR * 60 + mBR;

// Mapear dia da semana por nome (Intl retorna 'seg', 'ter', etc.)
const diaMap = { dom: 0, seg: 1, ter: 2, qua: 3, qui: 4, sex: 5, 'sГЎb': 6, sab: 6 };
const diaSemana = diaMap[dayName] !== undefined ? diaMap[dayName] : new Date(agora.getTime() - 3*60*60*1000).getUTCDay();

const horaInicio = loja.horario_inicio || '08:00';
const horaFim    = loja.horario_fim    || '18:00';
const [hIni, mIni] = horaInicio.split(':').map(Number);
const [hFim, mFim] = horaFim.split(':').map(Number);
const minutosInicio = hIni * 60 + mIni;
const minutosFim    = hFim * 60 + mFim;
const dentroHorario_hora = minutosAgora >= minutosInicio && minutosAgora <= minutosFim;

// Dias de funcionamento (ex: "seg,ter,qua,qui,sex")
const diasNumericos = { dom: 0, seg: 1, ter: 2, qua: 3, qui: 4, sex: 5, sab: 6 };
const diasFuncionamento = loja.dias_funcionamento
  ? loja.dias_funcionamento.split(',').map(d => diasNumericos[d.trim().toLowerCase()]).filter(d => d !== undefined)
  : null;
const dentroDia = !diasFuncionamento || diasFuncionamento.length === 0 || diasFuncionamento.includes(diaSemana);
const dentroHorario = dentroHorario_hora && dentroDia;

// Formatar histГіrico para o prompt
const historicoFormatado = historico
  .sort((a, b) => new Date(a.created_at) - new Date(b.created_at))
  .map(m => `${m.role === 'user' ? 'Cliente' : 'Assistente'}: ${m.content}`)
  .join('\n');

const primeiroContato = historico.length === 0;
const nomeAssistente = loja.nome_assistente || loja.nome_assistente_ia || 'Assistente';

return [{
  json: {
    // Dados do lead
    lead_id: lead.id,
    telefone: lead.telefone,
    nome_lead: lead.nome,
    etapa_pipeline: lead.etapa_pipeline,
    interesse_lead: lead.interesse,

    // Dados da loja
    loja_id: loja.id,
    nome_loja: loja.nome_loja,
    nome_assistente: nomeAssistente,
    tom_voz: loja.tom_voz || 'amigГЎvel, profissional e consultivo',
    especialidades: loja.especialidades || 'mГіveis e colchГөes',
    horario_inicio: horaInicio,
    horario_fim: horaFim,
    dias_funcionamento: loja.dias_funcionamento || 'seg,ter,qua,qui,sex',
    endereco: loja.endereco || 'Consulte-nos',
    maps_link: loja.maps_link || '',
    formas_pagamento: loja.formas_pagamento || 'Dinheiro, cartГЈo de crГ©dito/dГ©bito e PIX',
    politica_troca: loja.politica_troca || '30 dias para troca',
    prazo_entrega: loja.prazo_entrega || '7 a 15 dias Гәteis',
    frete_gratis_acima: loja.frete_gratis_acima || 1000,

    // Descontos
    desconto_carrinho_abandonado: loja.desconto_carrinho_abandonado || 5,
    desconto_promocao_nao_respondida: loja.desconto_promocao_nao_respondida || 10,
    desconto_followup_orcamento: loja.desconto_followup_orcamento || 5,

    // Config loja
    regras_personalidade: loja.regras_personalidade || '',
    plataforma_ecommerce: loja.plataforma_ecommerce || 'manual',
    checkout_base_url: loja.checkout_base_url || '',
    montagem_disponivel: loja.montagem_disponivel || false,

    // Dados do payload
    instance: payloadNode.instance,
    remoteJid: payloadNode.remoteJid,
    mensagem_usuario: payloadNode.mensagem_usuario,
    message_id: payloadNode.message_id,

    // Contexto para o agente
    historico_formatado: historicoFormatado,
    primeiro_contato: primeiroContato,
    dentroHorario: dentroHorario,
    msg_fora_horario: `OlГЎ! рҹҢҷ Nossa loja estГЎ fechada no momento.\nFuncionamos das ${horaInicio} Г s ${horaFim} (horГЎrio de BrasГӯlia), de ${loja.dias_funcionamento || 'seg a sex'}.\nDeixa sua mensagem que retornamos assim que abrirmos! рҹҳҠ`,

    // DEBUG вҖ” remova apГіs confirmar funcionamento
    _debug_horario: {
      utc_agora: agora.toISOString(),
      brt_hora: `${String(hBR).padStart(2,'0')}:${String(mBR).padStart(2,'0')}`,
      minutos_agora: minutosAgora,
      minutos_inicio: minutosInicio,
      minutos_fim: minutosFim,
      dentro_hora: dentroHorario_hora,
      dia_semana_num: diaSemana,
      dias_func_db: loja.dias_funcionamento,
      dentro_dia: dentroDia,
      dentroHorario: dentroHorario
    }
  }
}];

